fn main() {
    // loop - 无限循环
    let mut counter = 0;
    let result = loop {
        counter += 1;
        if counter == 10 {
            break counter * 2; // loop可以返回值
        }
    };
    println!("loop结果: {}", result);

    // while - 条件循环
    let mut num = 3;
    while num != 0 {
        println!("倒计时: {}!", num);
        num -= 1;
    }

    // for - 遍历循环(推荐)
    let arr = [10, 20, 30, 40, 50];
    for element in arr.iter() {
        println!("值: {}", element);
    }

    // Range
    for i in 1..5 {    // 1,2,3,4
        println!("i = {}", i);
    }
    for i in 1..=5 {   // 1,2,3,4,5
        println!("i = {}", i);
    }

    // 反向遍历
    for i in (1..4).rev() {
        println!("rev: {}", i);
    }
}

fn main() {
    // break退出循环
    let mut count = 0;
    loop {
        if count == 5 { break; }
        count += 1;
    }

    // break返回值
    let result = loop {
        count += 1;
        if count > 10 { break count; }
    };
    println!("break返回: {}", result);

    // continue跳过当前迭代
    for i in 1..=10 {
        if i % 2 == 0 { continue; } // 跳过偶数
        println!("奇数: {}", i);
    }

    // 标签break退出外层循环
    let mut found = false;
    'outer: for i in 0..5 {
        for j in 0..5 {
            if i * j == 6 {
                println!("找到: {}*{}=6", i, j);
                break 'outer; // 退出外层循环
            }
        }
    }
}

fn main() {
    // 规则1: 每个值有所有者
    let s1 = String::from("hello"); // s1拥有"hello"

    // 规则2: 移动语义 - 所有权转移
    let s2 = s1; // s1的所有权移动到s2
    // println!("{}", s1); // 错误！s1已失效

    // clone深拷贝
    let s3 = String::from("world");
    let s4 = s3.clone(); // 深拷贝，两个独立所有者
    println!("s3: {}, s4: {}", s3, s4);

    // 栈上数据: Copy语义(自动复制)
    let x = 5;
    let y = x; // i32实现了Copy trait，x仍然有效
    println!("x: {}, y: {}", x, y);

